import{_ as a,o as i,c as l,ae as t}from"./chunks/framework.wE_VpzFx.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note/我的项目/AI精简版-boss.md","filePath":"note/我的项目/AI精简版-boss.md"}'),r={name:"note/我的项目/AI精简版-boss.md"};function o(s,e,n,p,c,d){return i(),l("div",null,[...e[0]||(e[0]=[t('<h2 id="个人优势" tabindex="-1">个人优势 <a class="header-anchor" href="#个人优势" aria-label="Permalink to &quot;个人优势&quot;">​</a></h2><ol><li>扎实掌握 HTML、CSS、JavaScript、ES6+、TypeScript 等前端基础，熟悉常见数据结构、算法与设计模式。</li><li>精通 Vue 生态及源码，具备 PC 端、H5、Hybrid、微信小程序、Uni-app 等多端项目经验，并可协同 Vue / React 混合技术栈开发，且具有全栈开发经验。</li><li>熟悉 Webpack、Vite、Rollup、Babel、Node.js、Egg.js、Next.js 等技术，具备 SSR、性能优化、组件化与工程化落地经验。</li><li>擅长使用 Cursor、Claude Code、Codex 等 AI 开发工具进行工程化协作，能够结合 Plan、Skills 等能力沉淀高效研发协作范式，提升开发效率与工程落地质量。</li><li>具备团队级 AI 研发提效实践经验，搭建覆盖需求拆解、编码实现、测试验证到 Code Review 的 AI 辅助工作流，显著提升团队整体交付效率。</li></ol><h2 id="项目经历" tabindex="-1">项目经历 <a class="header-anchor" href="#项目经历" aria-label="Permalink to &quot;项目经历&quot;">​</a></h2><h3 id="bt教育平台" tabindex="-1">BT教育平台 <a class="header-anchor" href="#bt教育平台" aria-label="Permalink to &quot;BT教育平台&quot;">​</a></h3><p>项目描述：覆盖官网、管理后台、H5、Hybrid、小程序等多端形态，包含课程、直/录播、在线做题、支付、营销、社区等核心业务。作为前端负责人，负责平台前端整体架构、核心业务开发、技术管理、CI/CD、发布部署等工作。</p><p>技术栈：Vue2 / Vue3、React、TypeScript、UniApp、Vue Server Renderer、Vite、Webpack、qiankun、Egg.js、yjs 等。</p><p>核心贡献：</p><ol><li>搭建基于 Claude Code 的 AI 辅助研发工作流，依托 vercel-labs/skills 建立团队级 Skills 管理机制，覆盖需求分析、Vue/React 最佳实践编码、单元测试与端到端测试补全等关键环节，推动团队整体交付效率提升 100%。</li><li>将 CodeRabbit 接入 GitLab PR 流程，构建自动化代码评审能力，并基于 Prompt for AI Agents 生成可供 AI 编码工具消费的修复指令，提升评审效率与问题修复闭环速度。</li><li>主导官网 SSR 架构重构与性能治理，通过缓存、预加载、流式渲染、ISR 等方案，将首屏加载时间从 2.1s 降至 0.5s，页面秒开率提升至 90%，用户跳出率从 45% 降至 28%。</li><li>主导公司级微前端升级，基于 qiankun 在 3 个月内完成 10+ 历史项目集成，覆盖 Vue2 / Vue3 / React / 原生 JS；通过依赖共享和渐进迁移使首屏性能提升 40%，子应用接入成本从 3 天降至 2 小时。</li><li>设计并落地基于事件溯源 + CRDT 的答题数据同步方案，数据丢失率从 5% 降至 0.03%，弱网答题成功率提升至 99.5%，相关投诉下降 95.8%。</li></ol><h3 id="bt低代码平台" tabindex="-1">BT低代码平台 <a class="header-anchor" href="#bt低代码平台" aria-label="Permalink to &quot;BT低代码平台&quot;">​</a></h3><p>项目描述：面向企业内部运营的自研低代码平台，支持活动页、落地页的可视化搭建、发布、版本管理与跨平台投放。作为前端负责人，从 0 到 1 设计低代码平台整体架构，完成编排引擎、渲染引擎、变量系统、组件库、工程化体系建设。</p><p>技术栈：Vue3、TypeScript、pnpm、Vite、interactjs、CodeMirror 6 等。</p><p>核心贡献：</p><ol><li>采用 Monorepo + 插件化微内核 架构，并通过父子包分层维护 AGENTS.md，统一沉淀项目约束、文档入口及工程流程，提升 AI 对复杂工程上下文的理解与生成准确性，降低协作与试错成本。</li><li>自研拖拽放置引擎和嵌套布局算法，解决复杂容器下的拖拽定位问题；通过射线检测与父容器回溯策略，将放置准确率提升至 98% 以上。</li><li>针对复杂页面的全量渲染瓶颈，从响应式、渲染、拖拽、JSON 数据与增量更新等维度优化，使配置反馈延迟从 2-3 秒降至 200ms 以内，拖拽帧率稳定在 60 FPS。</li><li>设计三层调试体系和自定义调试面板，覆盖事件流、组件树、表达式执行、性能与内存分析；问题定位时间缩短 70%，线上 Bug 率下降 60%。</li><li>平台上线 6 个月后，内部应用开发效率提升约 60%；简单业务系统交付周期从 2 周缩短至 2-3 天，累计沉淀 60+ 通用组件、30+ 业务组件，支撑 200+ 页面交付，平台二次开发成本下降 70%。</li></ol><h3 id="前端全链路监控平台" tabindex="-1">前端全链路监控平台 <a class="header-anchor" href="#前端全链路监控平台" aria-label="Permalink to &quot;前端全链路监控平台&quot;">​</a></h3><p>项目描述：主导建设公司内部前端监控 SDK 与可视化分析平台，覆盖错误、性能、白屏、接口异常及用户行为轨迹采集分析。</p><p>技术栈：Vue3、TypeScript、Vite、Next.js、AntV、Kafka、ClickHouse</p><p>核心贡献：</p><ol><li>从 0 到 1 设计轻量级监控 SDK 与分析平台，支持错误、性能、行为埋点等能力按需启用，覆盖公司主站与后台 10+ 核心业务，日均处理百万级日志。</li><li>基于 Performance API 与 Web Vitals 建立性能基线，并设计首屏/白屏检测算法；通过 MutationObserver、关键资源判定与骨架屏过滤，将检测准确率提升至 95% 以上。</li><li>搭建统一异常上报与告警体系，结合 SourceMap、告警降噪、动态采样、冷热数据分离等方案，提升监控系统在高噪声场景下的可用性与排障效率。</li><li>通过对做题链路接口异常、超时分布和用户行为路径的关联分析，推动关键流程稳定性优化，使相关异常率从 5% 降至 0.3%；线上 JS 异常定位效率提升 60%，故障发现时效从小时级缩短至分钟级。</li><li>建立页面体验评级模型，定位课程详情页 LCP 瓶颈并推动优化，使 LCP 中位数从 2.8s 降至 1.6s，核心漏斗页面订单转化率提升 3%。</li></ol><h2 id="技术影响力" tabindex="-1">技术影响力 <a class="header-anchor" href="#技术影响力" aria-label="Permalink to &quot;技术影响力&quot;">​</a></h2><p><a href="https://juejin.cn/user/694547078987287/posts%EF%BC%88%E6%8E%98%E9%87%91%E4%BC%98%E7%A7%80%E5%88%9B%E4%BD%9C%E8%80%85%EF%BC%8C%E7%B4%AF%E8%AE%A1%E5%8F%91%E5%B8%8360+%E5%8E%9F%E5%88%9B%E6%8A%80%E6%9C%AF%E6%96%87%E7%AB%A0%EF%BC%89" target="_blank" rel="noreferrer">https://juejin.cn/user/694547078987287/posts（掘金优秀创作者，累计发布60+原创技术文章）</a></p>',20)])])}const b=a(r,[["render",o]]);export{h as __pageData,b as default};
